mapper.select:
select YYYYMM, 통화, 환율 from DOI_EXCHANGE_RATE where 1=1
and YYYYMM = #{yyyymm}
and 통화 = #{currency}
order by YYYYMM desc, 통화

mapper.insert:
INSERT INTO DOI_EXCHANGE_RATE
(
YYYYMM
, 통화
, 환율
, 등록자
, 등록일시
)
VALUES
(
#{yyyymm}
, #{통화}
, #{환율}
, #{dowInsysUserId}
, GETDATE()
);

mapper.update:
UPDATE DOI_EXCHANGE_RATE
SET 환율 = #{환율}
, 등록자 = #{dowInsysUserId}
, 등록일시 = GETDATE()
WHERE 1=1
and YYYYMM = #{yyyymm}
and 통화 = #{통화}
;

mapper.delete:
DELETE FROM DOI_EXCHANGE_RATE
WHERE 1=1
and YYYYMM = #{yyyymm}
and 통화 = #{통화}
;
